ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?audiencereviews WHERE {
  ?reviews a :Review .
  ?film a :Films .
  ?reviews p:hasFilm ?film .
  ?reviews p:AudienceReviews ?audiencereviews .
  ?film p:Title ?title_f .
  FILTER(STR(?title_f) = "Pulp Fiction")
} }
  component_2: { SELECT ?opinion WHERE {
  ?reviews a :Review .
  ?film a :Films .
  ?reviews p:hasFilm ?film .
  ?reviews p:Opinion ?opinion .
  ?film p:Title ?title_f .
  FILTER(STR(?title_f) = "Pulp Fiction")
} }
  full: { SELECT ?opinion ?audiencereviews WHERE {
  ?reviews a :Review .
  ?film a :Films .
  ?reviews p:hasFilm ?film .
  ?reviews p:Opinion ?opinion .
  ?reviews p:AudienceReviews ?audiencereviews .
  ?film p:Title ?title_f .
  FILTER(STR(?title_f) = "Pulp Fiction")
} }
}

